        if (eq(name, "findIndex")) {
            const cb = arg0(args);
            var i: usize = 0;
            while (i < ilen) : (i += 1) { // findIndex visits holes (value undefined)
                const el = try self.arrIndexGet(o, i);
                if ((try self.callValueWithThis(cb, &.{ el, .{ .number = @floatFromInt(i) }, .{ .object = o } }, cb_this)).toBoolean())
