                i -= 1;
                const el = try self.arrIndexGet(o, i); // visits holes (undefined)
                if ((try self.callValueWithThis(cb, &.{ el, .{ .number = @floatFromInt(i) }, .{ .object = o } }, cb_this)).toBoolean())
