            try ctor.setOwn(self_a, shp, "prototype", .{ .object = proto });
            try ctor.setAttr(self_a, "prototype", .{ .writable = false, .enumerable = false, .configurable = false });
            try setConstructor(self_a, shp, proto, ctor);
