        \\let it = ('a' + pair + 'b' + lo + pair + hi + lo)[Symbol.iterator]();
        \\let ok = it.next().value === 'a';
        \\ok = ok && it.next().value === pair;
        \\ok = ok && it.next().value === 'b';
        \\ok = ok && it.next().value === lo;
        \\ok = ok && it.next().value === pair;
        \\ok = ok && it.next().value === hi;
        \\ok = ok && it.next().value === lo;
        \\ok = ok && it.next().done === true;
